// ─────────────────────────────────────────────────────────────────────────────
// PROVIDER CONFIG NODE
// Configure your AI provider endpoint, model, and credential reference here.
// Do NOT hardcode real API keys. Use n8n credentials instead.
// ─────────────────────────────────────────────────────────────────────────────

const config = {
  // Replace with your provider's chat completions endpoint
  apiUrl: 'https://api.openai.com/v1/chat/completions',

  // Replace with your desired model identifier
  model: 'gpt-4o',

  // n8n credential name (HTTP Header Auth) — set up in n8n Credentials panel
  credentialName: 'YOUR_CREDENTIAL_NAME_HERE',

  // Request settings
  maxTokens: 1024,
  temperature: 0.2,

  // Retry settings for AI request nodes
  retryOnFail: true,
  maxTries: 3,
  waitBetweenTries: 2000,

  // Clustering thresholds (deterministic layer)
  thresholds: {
    minRevisitCount: 3,
    minDraftEdits: 3,
    minReopenCount: 2,
    minDeferCount: 2,
    lowSignalEventCount: 2
  }
};

return [
  {
    json: {
      ...items[0].json,
      _debug_provider_config: config,
      _debug_stage: 'provider_config'
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// NORMALIZE EVENTS NODE
// Validates and normalizes the incoming activity payload.
// Ensures all required fields are present and formats event data.
// ─────────────────────────────────────────────────────────────────────────────

const payload = items[0].json;
const config = payload._debug_provider_config;

// Validate required top-level fields
const required = ['user_id', 'analysis_mode', 'time_window_start', 'time_window_end', 'events'];
const missing = required.filter(f => !payload[f]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

if (!Array.isArray(payload.events) || payload.events.length === 0) {
  throw new Error('events must be a non-empty array');
}

// Normalize each event
const normalizedEvents = payload.events.map((evt, idx) => {
  if (!evt.timestamp || !evt.source || !evt.event_type || !evt.object_name) {
    throw new Error(`Event at index ${idx} is missing required fields (timestamp, source, event_type, object_name)`);
  }
  return {
    timestamp: evt.timestamp,
    source: evt.source.toLowerCase().trim(),
    event_type: evt.event_type.toLowerCase().trim(),
    object_name: evt.object_name.trim(),
    object_category: (evt.object_category || 'uncategorized').toLowerCase().trim(),
    session_id: evt.session_id || `session_auto_${idx}`
  };
});

// Sort events by timestamp ascending
normalizedEvents.sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));

return [
  {
    json: {
      user_id: payload.user_id,
      analysis_mode: payload.analysis_mode || 'single_loop',
      time_window_start: payload.time_window_start,
      time_window_end: payload.time_window_end,
      preferred_tone: payload.preferred_tone || 'direct',
      events: normalizedEvents,
      event_count: normalizedEvents.length,
      _debug_provider_config: config,
      _debug_stage: 'normalize_events',
      _debug_normalization_passed: true
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// CLUSTER REPEATED BEHAVIOR NODE
// Groups events by object_name + object_category.
// Counts opens, edits, revisits, defers, sends, submits per object.
// Identifies the primary object cluster for analysis.
// ─────────────────────────────────────────────────────────────────────────────

const data = items[0].json;
const events = data.events;
const thresholds = data._debug_provider_config.thresholds;

// Group events by object_name + object_category
const clusters = {};

for (const evt of events) {
  const key = `${evt.object_name}::${evt.object_category}`;
  if (!clusters[key]) {
    clusters[key] = {
      object_name: evt.object_name,
      object_category: evt.object_category,
      events: [],
      sessions: new Set(),
      event_type_counts: {}
    };
  }
  clusters[key].events.push(evt);
  clusters[key].sessions.add(evt.session_id);
  const et = evt.event_type;
  clusters[key].event_type_counts[et] = (clusters[key].event_type_counts[et] || 0) + 1;
}

// Compute derived counts per cluster
const clusterList = Object.values(clusters).map(c => {
  const etc = c.event_type_counts;
  return {
    object_name: c.object_name,
    object_category: c.object_category,
    total_events: c.events.length,
    unique_sessions: c.sessions.size,
    revisit_count: (etc['tab_open'] || 0) + (etc['item_open'] || 0) + (etc['file_open'] || 0) + (etc['reopen'] || 0),
    draft_edit_count: (etc['draft_edit'] || 0) + (etc['file_edit'] || 0) + (etc['edit'] || 0),
    reopen_count: etc['reopen'] || 0,
    defer_count: (etc['defer'] || 0) + (etc['snooze'] || 0) + (etc['postpone'] || 0),
    send_count: etc['send'] || 0,
    submit_count: (etc['submit'] || 0) + (etc['apply'] || 0),
    discard_count: (etc['discard'] || 0) + (etc['delete'] || 0) + (etc['archive'] || 0),
    event_type_counts: etc,
    first_seen: c.events[0].timestamp,
    last_seen: c.events[c.events.length - 1].timestamp,
    event_timeline: c.events.map(e => `[${e.timestamp}] ${e.event_type} (${e.source}, session: ${e.session_id})`)
  };
});

// Sort clusters by total_events descending, then by unique_sessions descending
clusterList.sort((a, b) => b.total_events - a.total_events || b.unique_sessions - a.unique_sessions);

// Select the primary cluster (highest signal)
const primaryCluster = clusterList[0] || null;

return [
  {
    json: {
      ...data,
      primary_cluster: primaryCluster,
      all_clusters: clusterList,
      cluster_count: clusterList.length,
      _debug_stage: 'cluster_repeated_behavior'
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// VALIDATE CLUSTER NODE
// Checks whether the primary cluster meets minimum thresholds for analysis.
// Marks low-signal clusters as invalid to prevent over-interpretation.
// ─────────────────────────────────────────────────────────────────────────────

const data = items[0].json;
const cluster = data.primary_cluster;
const thresholds = data._debug_provider_config.thresholds;

let isValid = false;
let invalidReason = null;

if (!cluster) {
  isValid = false;
  invalidReason = 'No cluster found in event data';
} else {
  const hasEnoughRevisits = cluster.revisit_count >= thresholds.minRevisitCount;
  const hasEnoughEdits = cluster.draft_edit_count >= thresholds.minDraftEdits;
  const hasEnoughReopens = cluster.reopen_count >= thresholds.minReopenCount;
  const hasEnoughDefers = cluster.defer_count >= thresholds.minDeferCount;
  const hasEnoughEvents = cluster.total_events > thresholds.lowSignalEventCount;

  if (!hasEnoughEvents) {
    isValid = false;
    invalidReason = `Total event count (${cluster.total_events}) is below low-signal threshold (${thresholds.lowSignalEventCount + 1})`;
  } else if (hasEnoughRevisits || hasEnoughEdits || hasEnoughReopens || hasEnoughDefers) {
    isValid = true;
  } else {
    isValid = false;
    invalidReason = 'Cluster does not meet minimum thresholds for any loop type (revisit, draft edit, reopen, defer)';
  }
}

return [
  {
    json: {
      ...data,
      cluster_is_valid: isValid,
      cluster_invalid_reason: invalidReason,
      _debug_stage: 'validate_cluster'
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// LOW SIGNAL RESPONSE NODE (False branch of If Valid)
// Returns a structured low-signal response without AI interpretation.
// ─────────────────────────────────────────────────────────────────────────────

const data = items[0].json;

const lowSignalResponse = {
  loop_summary: 'Insufficient behavioral signal to identify a meaningful loop pattern.',
  loop_type: 'low_signal_noise',
  friction_category: 'insufficient_data',
  severity_level: 'none',
  estimated_attention_leak: 'negligible',
  supporting_patterns: [],
  likely_blocker: null,
  recommended_intervention: 'Collect more behavioral data across a longer time window before analysis.',
  recommended_next_step: 'Expand the time window or add more event sources to the payload.',
  confidence_band: 'low',
  needs_human_review: false,
  review_reason: data.cluster_invalid_reason || 'Low signal'
};

return [
  {
    json: {
      _loop_analysis_result: lowSignalResponse,
      _debug_stage: 'low_signal_short_circuit',
      _debug_invalid_reason: data.cluster_invalid_reason
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// PREP LOOP ANALYSIS REQUEST NODE
// Constructs the system and user prompt messages for the AI loop analysis call.
// Prompts are loaded from the prompts/ directory and populated with cluster data.
// In production, load prompt files from disk or a connected storage node.
// ─────────────────────────────────────────────────────────────────────────────

const data = items[0].json;
const cluster = data.primary_cluster;
const config = data._debug_provider_config;

// ── SYSTEM PROMPT ──────────────────────────────────────────────────────────
// In production: load from prompts/system-loop-analysis.md
const systemPrompt = `You are a calm, precise behavioral-friction analyst.
Your role is to analyze a cluster of repeated digital behavior events and produce a structured JSON diagnostic.
You are not a therapist, motivational coach, or productivity advisor.
You work strictly from the behavioral signals provided.
You do not infer psychological states beyond what the data supports.
You do not use encouraging language, affirmations, or emotional framing.
You output strict JSON only — no markdown, no prose outside of JSON, no code fences.
All string values must be plain text.

Expected output fields:
- loop_summary: string. One to two sentence factual description of the observed pattern.
- loop_type: string. One of: reopen_loop, draft_churn_loop, revisit_without_commitment, defer_reopen_cycle, research_spiral, context_switch_drag, low_signal_noise, unresolved_open_loop.
- friction_category: string. One of: decision_avoidance, unclear_next_action, perfectionism_stall, dependency_block, priority_conflict, context_overload, insufficient_data, other.
- severity_level: string. One of: none, low, medium, high, critical.
- estimated_attention_leak: string. One of: negligible, low, moderate, high, severe.
- supporting_patterns: array of strings. Each entry is a short factual observation from the event data.
- likely_blocker: string or null. The most probable friction cause based on the signals.
- recommended_intervention: string. One specific, actionable intervention. Not generic advice.
- recommended_next_step: string. The single smallest useful move available.
- confidence_band: string. One of: low, medium, high.
- needs_human_review: boolean. True if the pattern is ambiguous, contradictory, or outside model competence.
- review_reason: string or null. Required if needs_human_review is true.`;

// ── USER PROMPT ────────────────────────────────────────────────────────────
// In production: load from prompts/user-loop-analysis-template.md and interpolate
const userPrompt = `Analyze the following repeated behavior cluster and return a JSON diagnostic.

ANALYSIS MODE: ${data.analysis_mode}
TIME WINDOW: ${data.time_window_start} to ${data.time_window_end}
EVENT COUNT: ${data.event_count}
PREFERRED TONE: ${data.preferred_tone}

PRIMARY CLUSTER:
- Repeated Object: ${cluster.object_name}
- Object Category: ${cluster.object_category}
- Total Events: ${cluster.total_events}
- Unique Sessions: ${cluster.unique_sessions}
- Revisit Count: ${cluster.revisit_count}
- Draft Edit Count: ${cluster.draft_edit_count}
- Reopen Count: ${cluster.reopen_count}
- Defer Count: ${cluster.defer_count}
- Send Count: ${cluster.send_count}
- Submit Count: ${cluster.submit_count}
- Discard Count: ${cluster.discard_count}
- First Seen: ${cluster.first_seen}
- Last Seen: ${cluster.last_seen}

EVENT TIMELINE:
${cluster.event_timeline.join('\n')}

INSTRUCTIONS:
- Base your analysis strictly on the signals above.
- Do not infer facts not supported by the event data.
- Do not output prose, markdown, or explanation outside of the JSON object.
- Return a single valid JSON object matching the expected schema.`;

const requestBody = {
  model: config.model,
  max_tokens: config.maxTokens,
  temperature: config.temperature,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [
  {
    json: {
      ...data,
      _debug_ai_request_body: requestBody,
      _debug_stage: 'prep_loop_analysis_request'
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// PARSE LOOP ANALYSIS NODE
// Extracts and validates the JSON response from the AI provider.
// Handles malformed output gracefully by setting needs_human_review = true.
// ─────────────────────────────────────────────────────────────────────────────

const aiResponse = items[0].json;
const previousData = $('Prep Loop Analysis Request').first().json;

let parsed = null;
let parseError = null;

try {
  // Extract the content from the AI response
  let content = '';
  if (aiResponse.choices && aiResponse.choices[0] && aiResponse.choices[0].message) {
    content = aiResponse.choices[0].message.content || '';
  } else if (aiResponse.content && Array.isArray(aiResponse.content)) {
    // Anthropic-style response
    content = aiResponse.content.map(c => c.text || '').join('');
  } else if (typeof aiResponse === 'string') {
    content = aiResponse;
  }

  // Strip code fences if model emitted them despite instructions
  content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

  parsed = JSON.parse(content);

  // Validate required output fields
  const requiredFields = [
    'loop_summary', 'loop_type', 'friction_category', 'severity_level',
    'estimated_attention_leak', 'supporting_patterns', 'likely_blocker',
    'recommended_intervention', 'recommended_next_step', 'confidence_band',
    'needs_human_review'
  ];

  const missingFields = requiredFields.filter(f => !(f in parsed));
  if (missingFields.length > 0) {
    parsed.needs_human_review = true;
    parsed.review_reason = `Model output missing required fields: ${missingFields.join(', ')}`;
  }

} catch (err) {
  parseError = err.message;
  parsed = {
    loop_summary: 'Model output could not be parsed as valid JSON.',
    loop_type: 'unresolved_open_loop',
    friction_category: 'insufficient_data',
    severity_level: 'low',
    estimated_attention_leak: 'low',
    supporting_patterns: [],
    likely_blocker: null,
    recommended_intervention: 'Retry the analysis with a fresh payload or inspect the AI provider response.',
    recommended_next_step: 'Check AI provider logs for malformed output.',
    confidence_band: 'low',
    needs_human_review: true,
    review_reason: `JSON parse failure: ${parseError}`
  };
}

return [
  {
    json: {
      ...previousData,
      _loop_analysis_result: parsed,
      _debug_ai_raw_response: aiResponse,
      _debug_parse_error: parseError,
      _debug_stage: 'parse_loop_analysis'
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// DETERMINISTIC FRICTION CHECKS NODE
// Applies rule-based post-processing to validate and supplement AI output.
// These checks run after AI interpretation and override or annotate the result
// where objective signal is stronger than model inference.
// ─────────────────────────────────────────────────────────────────────────────

const data = items[0].json;
const result = { ...data._loop_analysis_result };
const cluster = data.primary_cluster;
const thresholds = data._debug_provider_config.thresholds;

const deterministicFlags = [];

// Rule 1: Escalate severity if revisit_count is very high and send/submit is zero
if (cluster.revisit_count >= 8 && cluster.send_count === 0 && cluster.submit_count === 0) {
  if (result.severity_level === 'low' || result.severity_level === 'none') {
    result.severity_level = 'medium';
    deterministicFlags.push('SEVERITY_ESCALATED: High revisit count with no closure action detected');
  }
}

// Rule 2: Force loop type to draft_churn_loop if draft_edit_count is high and send_count is zero
if (cluster.draft_edit_count >= thresholds.minDraftEdits && cluster.send_count === 0) {
  if (result.loop_type !== 'draft_churn_loop') {
    deterministicFlags.push(`LOOP_TYPE_CORRECTED: draft_edit_count=${cluster.draft_edit_count}, send_count=0 is definitionally draft_churn_loop`);
    result.loop_type = 'draft_churn_loop';
  }
}

// Rule 3: Flag defer_reopen_cycle if defer_count and revisit_count both exceed threshold
if (cluster.defer_count >= thresholds.minDeferCount && cluster.revisit_count >= thresholds.minRevisitCount) {
  if (result.loop_type !== 'defer_reopen_cycle') {
    deterministicFlags.push(`LOOP_TYPE_CANDIDATE: defer_count=${cluster.defer_count} and revisit_count=${cluster.revisit_count} match defer_reopen_cycle pattern`);
  }
}

// Rule 4: Downgrade confidence if total_events is below 4
if (cluster.total_events < 4 && result.confidence_band === 'high') {
  result.confidence_band = 'medium';
  deterministicFlags.push('CONFIDENCE_DOWNGRADED: Total events below 4 — high confidence not warranted');
}

// Rule 5: Flag for human review if severity is critical
if (result.severity_level === 'critical' && !result.needs_human_review) {
  result.needs_human_review = true;
  result.review_reason = 'Critical severity flagged — human review recommended before acting on this result';
  deterministicFlags.push('HUMAN_REVIEW_FLAGGED: Critical severity threshold triggered');
}

return [
  {
    json: {
      ...data,
      _loop_analysis_result: result,
      _debug_deterministic_flags: deterministicFlags,
      _debug_stage: 'deterministic_friction_checks'
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// HUMAN REVIEW OVERRIDE NODE
// If needs_human_review is true, this node logs the flag and passes the result
// through with human_review_pending = true.
// In production: connect to a notification node (Slack, email, webhook) here.
// ─────────────────────────────────────────────────────────────────────────────

const data = items[0].json;
const result = data._loop_analysis_result;

const reviewPending = result.needs_human_review === true;

// In production: if reviewPending, trigger a notification to the review system.
// Example: connect an HTTP Request node to your Slack webhook or email endpoint.

return [
  {
    json: {
      ...data,
      _debug_human_review_pending: reviewPending,
      _debug_human_review_reason: result.review_reason || null,
      _debug_stage: 'human_review_override'
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// PREP WEEKLY PATTERN REVIEW NODE
// Constructs the system and user prompts for the weekly review call.
// Expects all_clusters to contain multiple analyzed loop results.
// In production: load prompt text from prompts/system-weekly-pattern-review.md
// ─────────────────────────────────────────────────────────────────────────────

const data = items[0].json;
const config = data._debug_provider_config;
const clusters = data.all_clusters || [];
const singleResult = data._loop_analysis_result;

// Build a JSON summary of loop results for the weekly prompt
const loopResultsSummary = JSON.stringify([
  singleResult,
  ...clusters.slice(1).map(c => ({
    object_name: c.object_name,
    object_category: c.object_category,
    total_events: c.total_events,
    revisit_count: c.revisit_count,
    draft_edit_count: c.draft_edit_count,
    defer_count: c.defer_count
  }))
], null, 2);

const weeklySystemPrompt = `You are a behavioral-friction pattern analyst reviewing a week of loop-analysis results.
Your role is to identify systemic patterns across multiple loop results and produce a structured weekly diagnostic.
You are not a therapist, coach, or advisor.
You work strictly from the loop-analysis outputs provided.
You do not infer patterns not supported by the data.
You output strict JSON only — no markdown, no prose outside JSON, no code fences.

Expected output fields:
- review_summary: string.
- top_loop_leaks: array of objects with object_name and loop_type.
- repeated_friction_categories: array of strings.
- recurring_blockers: array of strings.
- quick_closure_opportunities: array of strings.
- highest_severity_patterns: array of strings.
- next_week_interventions: array of strings.
- confidence_band: string. One of: low, medium, high.
- needs_human_review: boolean.
- review_reason: string or null.`;

const weeklyUserPrompt = `Analyze the following loop-analysis results from the past week and return a structured weekly pattern review.

TIME WINDOW: ${data.time_window_start} to ${data.time_window_end}
USER: ${data.user_id}
TOTAL CLUSTERS ANALYZED: ${clusters.length}

LOOP ANALYSIS RESULTS:
${loopResultsSummary}

INSTRUCTIONS:
- Identify patterns that appear across multiple loop results.
- Do not hallucinate patterns not present in the data.
- Return a single valid JSON object only.`;

const weeklyRequestBody = {
  model: config.model,
  max_tokens: config.maxTokens,
  temperature: 0.2,
  messages: [
    { role: 'system', content: weeklySystemPrompt },
    { role: 'user', content: weeklyUserPrompt }
  ]
};

return [
  {
    json: {
      ...data,
      _debug_weekly_request_body: weeklyRequestBody,
      _debug_stage: 'prep_weekly_pattern_review'
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// PARSE WEEKLY PATTERN REVIEW NODE
// Extracts and validates the JSON weekly review from the AI provider.
// ─────────────────────────────────────────────────────────────────────────────

const aiResponse = items[0].json;
const previousData = $('Prep Weekly Pattern Review').first().json;

let parsed = null;
let parseError = null;

try {
  let content = '';
  if (aiResponse.choices && aiResponse.choices[0] && aiResponse.choices[0].message) {
    content = aiResponse.choices[0].message.content || '';
  } else if (aiResponse.content && Array.isArray(aiResponse.content)) {
    content = aiResponse.content.map(c => c.text || '').join('');
  }
  content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
  parsed = JSON.parse(content);
} catch (err) {
  parseError = err.message;
  parsed = {
    review_summary: 'Weekly review output could not be parsed.',
    top_loop_leaks: [],
    repeated_friction_categories: [],
    recurring_blockers: [],
    quick_closure_opportunities: [],
    highest_severity_patterns: [],
    next_week_interventions: [],
    confidence_band: 'low',
    needs_human_review: true,
    review_reason: `JSON parse failure: ${parseError}`
  };
}

return [
  {
    json: {
      ...previousData,
      _weekly_review_result: parsed,
      _debug_weekly_parse_error: parseError,
      _debug_stage: 'parse_weekly_pattern_review'
    }
  }
];

// ─────────────────────────────────────────────────────────────────────────────
// FINAL RESPONSE NODE
// Assembles the clean public output.
// Strips all internal _debug_ fields before sending the response.
// Merges single-loop and optional weekly review results.
// ─────────────────────────────────────────────────────────────────────────────

const data = items[0].json;

// Extract clean results (no _debug_ fields)
const loopResult = data._loop_analysis_result || {};
const weeklyResult = data._weekly_review_result || null;

// Build the clean public response
const publicResponse = {
  status: 'success',
  analysis_mode: data.analysis_mode,
  user_id: data.user_id,
  time_window_start: data.time_window_start,
  time_window_end: data.time_window_end,
  loop_analysis: {
    loop_summary: loopResult.loop_summary,
    loop_type: loopResult.loop_type,
    friction_category: loopResult.friction_category,
    severity_level: loopResult.severity_level,
    estimated_attention_leak: loopResult.estimated_attention_leak,
    supporting_patterns: loopResult.supporting_patterns || [],
    likely_blocker: loopResult.likely_blocker || null,
    recommended_intervention: loopResult.recommended_intervention,
    recommended_next_step: loopResult.recommended_next_step,
    confidence_band: loopResult.confidence_band,
    needs_human_review: loopResult.needs_human_review || false,
    review_reason: loopResult.review_reason || null
  }
};

if (weeklyResult) {
  publicResponse.weekly_review = {
    review_summary: weeklyResult.review_summary,
    top_loop_leaks: weeklyResult.top_loop_leaks || [],
    repeated_friction_categories: weeklyResult.repeated_friction_categories || [],
    recurring_blockers: weeklyResult.recurring_blockers || [],
    quick_closure_opportunities: weeklyResult.quick_closure_opportunities || [],
    highest_severity_patterns: weeklyResult.highest_severity_patterns || [],
    next_week_interventions: weeklyResult.next_week_interventions || [],
    confidence_band: weeklyResult.confidence_band,
    needs_human_review: weeklyResult.needs_human_review || false,
    review_reason: weeklyResult.review_reason || null
  };
}

return [
  {
    json: publicResponse
  }
];
